mapper.select:
SELECT exam.id AS id, exam.name AS name, cla.id AS classId, cla.class_name AS className, grade.grade_group_name AS gradeGroupName, cla.sid AS schoolYear, semester.name AS periodName, exam.test_date AS testDate, subject.subject_name AS subjectName, exam.create_time AS createTime, susr.username AS updateUser, exam.remark AS remark FROM student_graduate_exam_task exam LEFT JOIN sys_class cla ON cla.id = exam.class_id LEFT JOIN grade_group grade ON grade.id = cla.grade_group LEFT JOIN sys_semester semester ON semester.id = exam.period_id LEFT JOIN subject_rel rel ON rel.id = exam.subject_id LEFT JOIN subject ON subject.id = rel.subject_id LEFT JOIN sys_user_school_rel susr ON susr.school_id = exam.school_id AND susr.user_id = exam.update_id AND susr.deleted = 0 WHERE exam.deleted = 0
AND exam.id IN
#{item}
AND exam.school_id = #{reqModel.schoolId}
AND cla.sid = #{reqModel.schoolYear}
AND exam.subject_id = #{reqModel.subjectId}
AND cla.grade_group = #{reqModel.gradeId}
AND cla.id = #{reqModel.classId}
AND exam.name LIKE CONCAT('%', #{reqModel.name}, '%')
AND exam.test_date >= #{reqModel.startTime}
AND exam.test_date <= #{reqModel.endTime}
AND cla.id IN
#{item}
ORDER BY exam.id DESC
